-- DMT_V_SUPPLIERS_DETAIL
CREATE OR REPLACE FORCE EDITIONABLE VIEW "DMT_V_SUPPLIERS_DETAIL" ("RUN_STATUS", "ERROR_TEXT", "RECONCILIATION_STATUS", "VENDOR_NAME", "IMPORT_ACTION", "VENDOR_NAME_NEW", "SEGMENT1", "VENDOR_NAME_ALT", "ORGANIZATION_TYPE_LOOKUP_CODE", "VENDOR_TYPE_LOOKUP_CODE", "END_DATE_ACTIVE", "BUSINESS_RELATIONSHIP", "PARENT_SUPPLIER_NAME", "ALIAS", "DUNS_NUMBER", "ONE_TIME_FLAG", "CUSTOMER_NUM", "STANDARD_INDUSTRY_CLASS", "NI_NUMBER", "CORPORATE_WEBSITE", "CHIEF_EXECUTIVE_TITLE", "CHIEF_EXECUTIVE_NAME", "BC_NOT_APPLICABLE_FLAG", "TAX_COUNTRY_CODE", "NUM_1099", "FEDERAL_REPORTABLE_FLAG", "TYPE_1099", "STATE_REPORTABLE_FLAG", "TAX_REPORTING_NAME", "NAME_CONTROL", "TAX_VERIFICATION_DATE", "ALLOW_AWT_FLAG", "AWT_GROUP_NAME", "VAT_CODE", "VAT_REGISTRATION_NUM", "AUTO_TAX_CALC_OVERRIDE", "PAYMENT_METHOD_LOOKUP_CODE", "DELIVERY_CHANNEL_CODE", "BANK_INSTRUCTION1_CODE", "BANK_INSTRUCTION2_CODE", "BANK_INSTRUCTION_DETAILS", "SETTLEMENT_PRIORITY", "PAYMENT_TEXT_MESSAGE1", "PAYMENT_TEXT_MESSAGE2", "PAYMENT_TEXT_MESSAGE3", "IBY_BANK_CHARGE_BEARER", "PAYMENT_REASON_CODE", "PAYMENT_REASON_COMMENTS", "PAYMENT_FORMAT_CODE", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "ATTRIBUTE16", "ATTRIBUTE17", "ATTRIBUTE18", "ATTRIBUTE19", "ATTRIBUTE20", "ATTRIBUTE_DATE1", "ATTRIBUTE_DATE2", "ATTRIBUTE_DATE3", "ATTRIBUTE_DATE4", "ATTRIBUTE_DATE5", "ATTRIBUTE_DATE6", "ATTRIBUTE_DATE7", "ATTRIBUTE_DATE8", "ATTRIBUTE_DATE9", "ATTRIBUTE_DATE10", "ATTRIBUTE_TIMESTAMP1", "ATTRIBUTE_TIMESTAMP2", "ATTRIBUTE_TIMESTAMP3", "ATTRIBUTE_TIMESTAMP4", "ATTRIBUTE_TIMESTAMP5", "ATTRIBUTE_TIMESTAMP6", "ATTRIBUTE_TIMESTAMP7", "ATTRIBUTE_TIMESTAMP8", "ATTRIBUTE_TIMESTAMP9", "ATTRIBUTE_TIMESTAMP10", "ATTRIBUTE_NUMBER1", "ATTRIBUTE_NUMBER2", "ATTRIBUTE_NUMBER3", "ATTRIBUTE_NUMBER4", "ATTRIBUTE_NUMBER5", "ATTRIBUTE_NUMBER6", "ATTRIBUTE_NUMBER7", "ATTRIBUTE_NUMBER8", "ATTRIBUTE_NUMBER9", "ATTRIBUTE_NUMBER10", "GLOBAL_ATTRIBUTE_CATEGORY", "GLOBAL_ATTRIBUTE1", "GLOBAL_ATTRIBUTE2", "GLOBAL_ATTRIBUTE3", "GLOBAL_ATTRIBUTE4", "GLOBAL_ATTRIBUTE5", "GLOBAL_ATTRIBUTE6", "GLOBAL_ATTRIBUTE7", "GLOBAL_ATTRIBUTE8", "GLOBAL_ATTRIBUTE9", "GLOBAL_ATTRIBUTE10", "GLOBAL_ATTRIBUTE11", "GLOBAL_ATTRIBUTE12", "GLOBAL_ATTRIBUTE13", "GLOBAL_ATTRIBUTE14", "GLOBAL_ATTRIBUTE15", "GLOBAL_ATTRIBUTE16", "GLOBAL_ATTRIBUTE17", "GLOBAL_ATTRIBUTE18", "GLOBAL_ATTRIBUTE19", "GLOBAL_ATTRIBUTE20", "GLOBAL_ATTRIBUTE_DATE1", "GLOBAL_ATTRIBUTE_DATE2", "GLOBAL_ATTRIBUTE_DATE3", "GLOBAL_ATTRIBUTE_DATE4", "GLOBAL_ATTRIBUTE_DATE5", "GLOBAL_ATTRIBUTE_DATE6", "GLOBAL_ATTRIBUTE_DATE7", "GLOBAL_ATTRIBUTE_DATE8", "GLOBAL_ATTRIBUTE_DATE9", "GLOBAL_ATTRIBUTE_DATE10", "GLOBAL_ATTRIBUTE_TIMESTAMP1", "GLOBAL_ATTRIBUTE_TIMESTAMP2", "GLOBAL_ATTRIBUTE_TIMESTAMP3", "GLOBAL_ATTRIBUTE_TIMESTAMP4", "GLOBAL_ATTRIBUTE_TIMESTAMP5", "GLOBAL_ATTRIBUTE_TIMESTAMP6", "GLOBAL_ATTRIBUTE_TIMESTAMP7", "GLOBAL_ATTRIBUTE_TIMESTAMP8", "GLOBAL_ATTRIBUTE_TIMESTAMP9", "GLOBAL_ATTRIBUTE_TIMESTAMP10", "GLOBAL_ATTRIBUTE_NUMBER1", "GLOBAL_ATTRIBUTE_NUMBER2", "GLOBAL_ATTRIBUTE_NUMBER3", "GLOBAL_ATTRIBUTE_NUMBER4", "GLOBAL_ATTRIBUTE_NUMBER5", "GLOBAL_ATTRIBUTE_NUMBER6", "GLOBAL_ATTRIBUTE_NUMBER7", "GLOBAL_ATTRIBUTE_NUMBER8", "GLOBAL_ATTRIBUTE_NUMBER9", "GLOBAL_ATTRIBUTE_NUMBER10", "PARTY_NUMBER", "SERVICE_LEVEL_CODE", "EXCLUSIVE_PAYMENT_FLAG", "REMIT_ADVICE_DELIVERY_METHOD", "REMIT_ADVICE_EMAIL", "REMIT_ADVICE_FAX", "DATAFOX_COMPANY_ID", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "INTEGRATION_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    -- 1. Run status
    NVL(tfm.TFM_STATUS, stg.STG_STATUS)                             AS RUN_STATUS,
    -- 2. Error text
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    -- 3. Human identifier
    stg.VENDOR_NAME                                         AS VENDOR_NAME,
    -- 4. All remaining STG business columns
    stg.IMPORT_ACTION,
    stg.VENDOR_NAME_NEW,
    stg.SEGMENT1,
    stg.VENDOR_NAME_ALT,
    stg.ORGANIZATION_TYPE_LOOKUP_CODE,
    stg.VENDOR_TYPE_LOOKUP_CODE,
    stg.END_DATE_ACTIVE,
    stg.BUSINESS_RELATIONSHIP,
    stg.PARENT_SUPPLIER_NAME,
    stg.ALIAS,
    stg.DUNS_NUMBER,
    stg.ONE_TIME_FLAG,
    stg.CUSTOMER_NUM,
    stg.STANDARD_INDUSTRY_CLASS,
    stg.NI_NUMBER,
    stg.CORPORATE_WEBSITE,
    stg.CHIEF_EXECUTIVE_TITLE,
    stg.CHIEF_EXECUTIVE_NAME,
    stg.BC_NOT_APPLICABLE_FLAG,
    stg.TAX_COUNTRY_CODE,
    stg.NUM_1099,
    stg.FEDERAL_REPORTABLE_FLAG,
    stg.TYPE_1099,
    stg.STATE_REPORTABLE_FLAG,
    stg.TAX_REPORTING_NAME,
    stg.NAME_CONTROL,
    stg.TAX_VERIFICATION_DATE,
    stg.ALLOW_AWT_FLAG,
    stg.AWT_GROUP_NAME,
    stg.VAT_CODE,
    stg.VAT_REGISTRATION_NUM,
    stg.AUTO_TAX_CALC_OVERRIDE,
    stg.PAYMENT_METHOD_LOOKUP_CODE,
    stg.DELIVERY_CHANNEL_CODE,
    stg.BANK_INSTRUCTION1_CODE,
    stg.BANK_INSTRUCTION2_CODE,
    stg.BANK_INSTRUCTION_DETAILS,
    stg.SETTLEMENT_PRIORITY,
    stg.PAYMENT_TEXT_MESSAGE1,
    stg.PAYMENT_TEXT_MESSAGE2,
    stg.PAYMENT_TEXT_MESSAGE3,
    stg.IBY_BANK_CHARGE_BEARER,
    stg.PAYMENT_REASON_CODE,
    stg.PAYMENT_REASON_COMMENTS,
    stg.PAYMENT_FORMAT_CODE,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
    stg.ATTRIBUTE3,
    stg.ATTRIBUTE4,
    stg.ATTRIBUTE5,
    stg.ATTRIBUTE6,
    stg.ATTRIBUTE7,
    stg.ATTRIBUTE8,
    stg.ATTRIBUTE9,
    stg.ATTRIBUTE10,
    stg.ATTRIBUTE11,
    stg.ATTRIBUTE12,
    stg.ATTRIBUTE13,
    stg.ATTRIBUTE14,
    stg.ATTRIBUTE15,
    stg.ATTRIBUTE16,
    stg.ATTRIBUTE17,
    stg.ATTRIBUTE18,
    stg.ATTRIBUTE19,
    stg.ATTRIBUTE20,
    stg.ATTRIBUTE_DATE1,
    stg.ATTRIBUTE_DATE2,
    stg.ATTRIBUTE_DATE3,
    stg.ATTRIBUTE_DATE4,
    stg.ATTRIBUTE_DATE5,
    stg.ATTRIBUTE_DATE6,
    stg.ATTRIBUTE_DATE7,
    stg.ATTRIBUTE_DATE8,
    stg.ATTRIBUTE_DATE9,
    stg.ATTRIBUTE_DATE10,
    stg.ATTRIBUTE_TIMESTAMP1,
    stg.ATTRIBUTE_TIMESTAMP2,
    stg.ATTRIBUTE_TIMESTAMP3,
    stg.ATTRIBUTE_TIMESTAMP4,
    stg.ATTRIBUTE_TIMESTAMP5,
    stg.ATTRIBUTE_TIMESTAMP6,
    stg.ATTRIBUTE_TIMESTAMP7,
    stg.ATTRIBUTE_TIMESTAMP8,
    stg.ATTRIBUTE_TIMESTAMP9,
    stg.ATTRIBUTE_TIMESTAMP10,
    stg.ATTRIBUTE_NUMBER1,
    stg.ATTRIBUTE_NUMBER2,
    stg.ATTRIBUTE_NUMBER3,
    stg.ATTRIBUTE_NUMBER4,
    stg.ATTRIBUTE_NUMBER5,
    stg.ATTRIBUTE_NUMBER6,
    stg.ATTRIBUTE_NUMBER7,
    stg.ATTRIBUTE_NUMBER8,
    stg.ATTRIBUTE_NUMBER9,
    stg.ATTRIBUTE_NUMBER10,
    stg.GLOBAL_ATTRIBUTE_CATEGORY,
    stg.GLOBAL_ATTRIBUTE1,
    stg.GLOBAL_ATTRIBUTE2,
    stg.GLOBAL_ATTRIBUTE3,
    stg.GLOBAL_ATTRIBUTE4,
    stg.GLOBAL_ATTRIBUTE5,
    stg.GLOBAL_ATTRIBUTE6,
    stg.GLOBAL_ATTRIBUTE7,
    stg.GLOBAL_ATTRIBUTE8,
    stg.GLOBAL_ATTRIBUTE9,
    stg.GLOBAL_ATTRIBUTE10,
    stg.GLOBAL_ATTRIBUTE11,
    stg.GLOBAL_ATTRIBUTE12,
    stg.GLOBAL_ATTRIBUTE13,
    stg.GLOBAL_ATTRIBUTE14,
    stg.GLOBAL_ATTRIBUTE15,
    stg.GLOBAL_ATTRIBUTE16,
    stg.GLOBAL_ATTRIBUTE17,
    stg.GLOBAL_ATTRIBUTE18,
    stg.GLOBAL_ATTRIBUTE19,
    stg.GLOBAL_ATTRIBUTE20,
    stg.GLOBAL_ATTRIBUTE_DATE1,
    stg.GLOBAL_ATTRIBUTE_DATE2,
    stg.GLOBAL_ATTRIBUTE_DATE3,
    stg.GLOBAL_ATTRIBUTE_DATE4,
    stg.GLOBAL_ATTRIBUTE_DATE5,
    stg.GLOBAL_ATTRIBUTE_DATE6,
    stg.GLOBAL_ATTRIBUTE_DATE7,
    stg.GLOBAL_ATTRIBUTE_DATE8,
    stg.GLOBAL_ATTRIBUTE_DATE9,
    stg.GLOBAL_ATTRIBUTE_DATE10,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP1,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP2,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP3,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP4,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP5,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP6,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP7,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP8,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP9,
    stg.GLOBAL_ATTRIBUTE_TIMESTAMP10,
    stg.GLOBAL_ATTRIBUTE_NUMBER1,
    stg.GLOBAL_ATTRIBUTE_NUMBER2,
    stg.GLOBAL_ATTRIBUTE_NUMBER3,
    stg.GLOBAL_ATTRIBUTE_NUMBER4,
    stg.GLOBAL_ATTRIBUTE_NUMBER5,
    stg.GLOBAL_ATTRIBUTE_NUMBER6,
    stg.GLOBAL_ATTRIBUTE_NUMBER7,
    stg.GLOBAL_ATTRIBUTE_NUMBER8,
    stg.GLOBAL_ATTRIBUTE_NUMBER9,
    stg.GLOBAL_ATTRIBUTE_NUMBER10,
    stg.PARTY_NUMBER,
    stg.SERVICE_LEVEL_CODE,
    stg.EXCLUSIVE_PAYMENT_FLAG,
    stg.REMIT_ADVICE_DELIVERY_METHOD,
    stg.REMIT_ADVICE_EMAIL,
    stg.REMIT_ADVICE_FAX,
    stg.DATAFOX_COMPANY_ID,
    stg.SOURCE_ID,
    -- 5. STG_SEQUENCE_ID
    stg.STG_SEQUENCE_ID,
    -- 6. RUN_ID (+ INTEGRATION_ID compat alias â legacy APEX IRs still reference INTEGRATION_ID)
    tfm.RUN_ID,
    tfm.RUN_ID                                              AS INTEGRATION_ID,
    -- 7. PREFIX (from PIPELINE_RUN)
    cm.PREFIX,
    -- 8. SCENARIO_ID
    stg.SCENARIO_ID,
    -- 9. STAGE_DATE
    stg.STAGE_DATE,
    -- 10. LAST_UPDATED_DATE
    NVL(tfm.LAST_UPDATED_DATE, stg.LAST_UPDATED_DATE)      AS LAST_UPDATED_DATE
FROM DMT_OWNER.DMT_POZ_SUPPLIERS_STG_TBL stg
LEFT JOIN (
    SELECT t.*,
           ROW_NUMBER() OVER (PARTITION BY t.STG_SEQUENCE_ID
                              ORDER BY t.TFM_SEQUENCE_ID DESC) AS rn
    FROM   DMT_OWNER.DMT_POZ_SUPPLIERS_TFM_TBL t
) tfm ON tfm.STG_SEQUENCE_ID = stg.STG_SEQUENCE_ID AND tfm.rn = 1
LEFT JOIN DMT_OWNER.DMT_PIPELINE_RUN_TBL cm
    ON cm.RUN_ID = tfm.RUN_ID;
